head.script:
(function () {
  var XHTML_NS = 'http://www.w3.org/1999/xhtml';
  var root = document.querySelector('foreignObject').firstElementChild;
  var head = root.querySelector('head');
  var body = root.querySelector('body');
  var _ce  = document.createElement.bind(document);
  var _ceNS = document.createElementNS.bind(document);
  Object.defineProperty(document, 'head',            { get: function () { return head; }, configurable: true });
  Object.defineProperty(document, 'body',            { get: function () { return body; }, configurable: true });
  Object.defineProperty(document, 'documentElement', { get: function () { return root; }, configurable: true });
  document.createElement = function (tag, opts) { return typeof tag === 'string' ? _ceNS(XHTML_NS, tag, opts) : _ce(tag, opts); };
  document.createElementNS = function (ns, q, opts) { return (ns == null || ns === XHTML_NS) ? _ceNS(XHTML_NS, q, opts) : _ceNS(ns, q, opts); };
  if (!location.hash) { try { history.replaceState(history.state, '', '#/'); } catch (e) {} }
})();
